// ============================================================
// SUPABASE — core data sync (orders / payments / products / trash / fraudList)
// ============================================================
// This is the layer that makes the Dashboard show the SAME data on your
// laptop and your phone. db.js's loadDB()/saveDB() still write to
// localStorage as an instant, offline-safe local cache — but whenever
// Supabase is configured, this file is what fetches the real, shared,
// up-to-date copy and pushes local edits back up.
//
// Design notes:
//  - Every record (order/payment/product/trash item/fraud entry) is stored
//    as one row: { id, data, updated_at }. `data` holds the entire JS
//    object as-is, so new fields added to orders/payments/etc. later don't
//    require another SQL migration.
//  - syncDBToSupabase() diffs against a `snapshot` (a Map<id, json-string>
//    per collection) rather than the previous React state object, because
//    every screen in this app mutates `db.orders`/`db.trash`/etc. IN PLACE
//    before calling setDb() — so by the time we'd compare "previous vs
//    next" state, they're often already the same mutated array. The
//    snapshot is captured separately (plain strings, immune to that) right
//    after each successful sync, so the diff is always accurate.
//  - A collection that fails to sync (offline, RLS error, etc.) keeps its
//    OLD snapshot, so the next save attempt will see those rows as "still
//    different" and retry them automatically — no edits get silently lost.

import { getClient, isSupabaseConfigured } from './supabase.js';

const TABLES = {
  orders:    'oms_orders',
  payments:  'oms_payments',
  products:  'oms_products',
  trash:     'oms_trash',
  fraudList: 'oms_fraud_list',
};

function rowsToArray(rows) {
  return (rows || []).map((r) => ({ ...(r.data || {}), id: r.id }));
}

// Fetches the current, real, shared data straight from Supabase — no
// cache, no localStorage involved. Throws if not configured or unreachable;
// callers decide how to fall back (see App.jsx refreshFromSupabase).
export async function fetchFreshDB() {
  const client = await getClient();
  if (!client) throw new Error('Supabase is not configured');

  const keys = Object.keys(TABLES);
  const results = await Promise.all(
    keys.map((key) => client.from(TABLES[key]).select('id, data'))
  );

  const out = {};
  results.forEach((res, i) => {
    const key = keys[i];
    if (res.error) throw res.error;
    out[key] = rowsToArray(res.data);
  });
  return out; // { orders, payments, products, trash, fraudList }
}

// Builds a snapshot of the given db state: Map<id, JSON string> per
// collection. Used as the diff baseline for syncDBToSupabase — capture
// this right after a successful fetch or push.
export function snapshotIds(db) {
  const snap = {};
  for (const key of Object.keys(TABLES)) {
    const map = new Map();
    (db?.[key] || []).forEach((r) => {
      if (r && r.id) map.set(r.id, JSON.stringify(r));
    });
    snap[key] = map;
  }
  return snap;
}

// Guards against data loss: if some records exist ONLY in `localDb` (not
// yet in `freshDb` — e.g. this device was offline when it made an edit, or
// this is the first time THIS device has connected to Supabase while it
// already had local orders), folds those records into the result rather
// than letting a refresh silently overwrite them with the remote copy.
// Returns the merged db plus a per-collection count of what was rescued,
// so the caller can tell the person what happened.
export function mergeMissingLocalIntoFresh(freshDb, localDb) {
  const merged = {};
  const rescued = {};
  for (const key of Object.keys(TABLES)) {
    const freshArr = freshDb?.[key] || [];
    const localArr = localDb?.[key] || [];
    const freshIds = new Set(freshArr.map((r) => r && r.id));
    const missingLocal = localArr.filter((r) => r && r.id && !freshIds.has(r.id));
    merged[key] = [...freshArr, ...missingLocal];
    if (missingLocal.length) rescued[key] = missingLocal.length;
  }
  return { merged, rescued };
}


// Supabase: upserts new/changed rows, deletes rows that disappeared
// (e.g. permanently deleted from Trash). Returns the snapshot to store for
// the next call, plus which collections (if any) failed.
export async function syncDBToSupabase(nextDb, prevSnapshot) {
  if (!isSupabaseConfigured()) {
    return { ok: false, errors: ['not_configured'], snapshot: prevSnapshot };
  }
  const client = await getClient();
  if (!client) return { ok: false, errors: ['not_configured'], snapshot: prevSnapshot };

  const errors = [];
  const nextSnapshot = {};

  await Promise.all(Object.keys(TABLES).map(async (key) => {
    const table = TABLES[key];
    const arr = nextDb?.[key] || [];
    const prevMap = prevSnapshot?.[key] || new Map();
    const nextMap = new Map();
    const toUpsert = [];

    arr.forEach((r) => {
      if (!r || !r.id) return;
      const json = JSON.stringify(r);
      nextMap.set(r.id, json);
      if (prevMap.get(r.id) !== json) {
        toUpsert.push({ id: r.id, data: r, updated_at: new Date().toISOString() });
      }
    });

    const toDelete = [...prevMap.keys()].filter((id) => !nextMap.has(id));

    try {
      if (toUpsert.length) {
        const { error } = await client.from(table).upsert(toUpsert, { onConflict: 'id' });
        if (error) throw error;
      }
      if (toDelete.length) {
        const { error } = await client.from(table).delete().in('id', toDelete);
        if (error) throw error;
      }
      nextSnapshot[key] = nextMap;
    } catch (e) {
      console.error(`Supabase sync failed for ${table} (will retry on next save):`, e);
      errors.push(key);
      nextSnapshot[key] = prevMap; // keep old snapshot so these rows are retried next time
    }
  }));

  return { ok: errors.length === 0, errors, snapshot: nextSnapshot };
}

// ============================================================
// REALTIME — live updates across devices (laptop + mobile)
// ============================================================
// Opens ONE Supabase Realtime channel and listens for postgres_changes
// (insert/update/delete) on all five core tables at once. Whenever ANY
// row changes — on this device or any other device signed into the same
// Supabase project — `onChange` fires so the caller (App.jsx) can pull
// the fresh data down, instead of waiting for the next manual "Refresh
// Data" click or page load.
//
// Returns an unsubscribe function. Safe no-op (returns a no-op unsubscribe)
// if Supabase isn't configured, so this can be called unconditionally.
//
// NOTE: Realtime must also be turned on for these tables on the Supabase
// side — see the "ENABLE REALTIME" section added to supabase_schema.sql.
// Postgres changes aren't broadcast to any client until each table is
// added to the `supabase_realtime` publication; this client-side listener
// alone is not enough.
export function subscribeToChanges(onChange) {
  let unsubscribed = false;
  let channel = null;

  (async () => {
    if (!isSupabaseConfigured()) return;
    const client = await getClient();
    if (!client || unsubscribed) return;

    channel = client.channel('oms_realtime_changes');
    Object.entries(TABLES).forEach(([key, table]) => {
      channel.on(
        'postgres_changes',
        { event: '*', schema: 'public', table },
        (payload) => onChange(key, payload)
      );
    });
    channel.subscribe((status, err) => {
      if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
        console.error(`Supabase realtime channel ${status} (non-fatal — falls back to manual/login refresh):`, err);
      }
    });
  })();

  return function unsubscribe() {
    unsubscribed = true;
    if (channel) {
      channel.unsubscribe();
      channel = null;
    }
  };
}

// ============================================================
// COURIER-WISE ANALYTICS — Supabase-side aggregate (optional)
// ============================================================
// Wraps the `oms_courier_breakdown()` SQL function (see supabase_schema.sql)
// for callers that want the Platform → Courier → Status counts computed
// in Postgres instead of in the browser — useful once the orders table
// gets large enough that pulling every row just to count it stops being
// the right call. The Dashboard itself doesn't need this: it already has
// every order in memory and uses flattenCourierBreakdown() from db.js
// directly, with no round trip.
//
// Returns { rows, error } and NEVER throws — every failure mode (not
// configured, network down, the SQL function not yet created because
// this user hasn't run the latest supabase_schema.sql, RLS denying the
// call, etc.) comes back as `{ rows: [], error: <message> }` so a caller
// can render "no data" instead of crashing. A courier/platform combo with
// genuinely zero orders is NOT an error — it simply won't appear as a row,
// the same way it wouldn't appear in a GROUP BY with no matching rows.
export async function fetchCourierBreakdown() {
  if (!isSupabaseConfigured()) {
    return { rows: [], error: 'not_configured' };
  }
  try {
    const client = await getClient();
    if (!client) return { rows: [], error: 'not_configured' };

    const { data, error } = await client.rpc('oms_courier_breakdown');
    if (error) throw error;

    return { rows: data || [], error: null };
  } catch (e) {
    // Common cause: the SQL function hasn't been created yet on this
    // Supabase project (older deployments that haven't re-run
    // supabase_schema.sql). Surface a clear reason instead of a raw
    // Postgres error string where possible.
    const reason = /function .* does not exist/i.test(e?.message || '')
      ? 'oms_courier_breakdown() SQL function not found — run the latest supabase_schema.sql in the Supabase SQL Editor'
      : (e?.message || 'unknown error');
    console.error('fetchCourierBreakdown failed (non-fatal):', e);
    return { rows: [], error: reason };
  }
}

// ============================================================
// HISTORICAL DATA MIGRATION
// ============================================================
// Pushes the 739-order / 443-trash-record historical dataset from
// the todaydata.json + prior history (merged) export directly into
// Supabase so it is immediately visible on every device.
//
// Called from App.jsx's Settings panel ("Migrate Historical Data"
// button). Uses ON CONFLICT / upsert so it is safe to call more
// than once — existing records are untouched, missing ones are added.
//
// The historical data is embedded directly in this file as a JS
// constant so the migration works without any additional file upload
// or network fetch. Changing or re-importing the data only requires
// updating HISTORICAL_DATA below and re-deploying.
//
// SQL equivalent (for reference / manual migration):
//   → see migrate_historical_data.sql in the project root.
//
// Returns { inserted, skipped, errors } summary.
export async function migrateHistoricalData(onProgress) {
  if (!isSupabaseConfigured()) {
    return { ok: false, error: 'Supabase is not configured. Add your URL and anon key in Settings first.' };
  }
  const client = await getClient();
  if (!client) {
    return { ok: false, error: 'Could not connect to Supabase.' };
  }

  const TABLE_MAP = {
    orders:    'oms_orders',
    payments:  'oms_payments',
    products:  'oms_products',
    trash:     'oms_trash',
    fraudList: 'oms_fraud_list',
  };

  let totalInserted = 0, totalErrors = 0;
  const errorDetails = [];
  const now = new Date().toISOString();

  for (const [key, table] of Object.entries(TABLE_MAP)) {
    const records = (HISTORICAL_DATA[key] || []).filter((r) => r && r.id);
    if (!records.length) continue;

    if (typeof onProgress === 'function') {
      onProgress(`Uploading ${records.length} ${key}…`);
    }

    // Upsert in chunks of 50 to stay well within Supabase request limits
    const CHUNK = 50;
    for (let start = 0; start < records.length; start += CHUNK) {
      const chunk = records.slice(start, start + CHUNK);
      const rows  = chunk.map((r) => ({ id: r.id, data: r, updated_at: now }));
      const { error } = await client.from(table).upsert(rows, { onConflict: 'id', ignoreDuplicates: true });
      if (error) {
        totalErrors++;
        errorDetails.push(`${table} chunk@${start}: ${error.message}`);
      } else {
        totalInserted += chunk.length;
      }
    }
  }

  return {
    ok: totalErrors === 0,
    inserted: totalInserted,
    errors: totalErrors,
    errorDetails,
  };
}

